#!/usr/bin/env tsx
/**
 * Exa research — create and manage deep research tasks.
 *
 * Usage:
 *   tsx scripts/research.ts create <instructions> [options-json]
 *   tsx scripts/research.ts get <research-id> [options-json]
 *   tsx scripts/research.ts poll <research-id> [options-json]
 *   tsx scripts/research.ts list [options-json]
 *   tsx scripts/research.ts run <instructions> [options-json]
 *   tsx scripts/research.ts --help
 *
 * Subcommands:
 *   create   — Start a new research task (returns immediately with researchId)
 *   get      — Get the current status/result of a research task
 *   poll     — Poll an existing task until finished (blocks until complete)
 *   list     — List research tasks
 *   run      — Create + poll in one step (convenience)
 *
 * Options JSON for create/run:
 *   {
 *     "model": "exa-research-fast",   // "exa-research-fast"|"exa-research"|"exa-research-pro"
 *     "outputSchema": {}              // JSON Schema for structured output
 *   }
 *
 * Options JSON for get:
 *   {
 *     "stream": false,                // stream SSE events
 *     "events": false                 // include event log
 *   }
 *
 * Options JSON for poll:
 *   {
 *     "pollInterval": 2000,           // ms between polls (default 2000)
 *     "timeoutMs": 600000,            // max wait time (default 10 min)
 *     "events": false
 *   }
 *
 * Options JSON for list:
 *   {
 *     "limit": 10,
 *     "cursor": "..."
 *   }
 *
 * Environment:
 *   EXA_API_KEY — required
 *
 * Examples:
 *   tsx scripts/research.ts create "Research the latest AI developments"
 *   tsx scripts/research.ts get "a1b2c3d4-e5f6-7890-abcd-ef1234567890"
 *   tsx scripts/research.ts run "What is SpaceX's latest valuation?" '{"model":"exa-research-pro"}'
 *   tsx scripts/research.ts list '{"limit":5}'
 */

import {
  showHelp,
  requireApiKey,
  handleError,
  requireArg,
  createClient,
  executeAndPrint,
} from './lib/common.js'

// research.ts has a subcommand pattern: parseArgs assumes args[1] is JSON opts,
// which conflicts with create/run where args[1] is instructions text. Use
// showHelp directly and index process.argv by position instead.
if (process.argv.includes('--help') || process.argv.length <= 2) {
  showHelp(import.meta.url)
}

const subcommand = process.argv[2]
const arg1 = process.argv[3]

requireApiKey()

const exa = createClient()

try {
  switch (subcommand) {
    case 'create': {
      const instructions = requireArg(arg1, 'instructions')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () =>
        exa.research.create({
          instructions,
          model:
            (opts.model as 'exa-research-fast' | 'exa-research' | 'exa-research-pro') ?? undefined,
          outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
        }),
      )
      break
    }

    case 'get': {
      const researchId = requireArg(arg1, 'research-id')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      if (opts.stream) {
        const streamResult = await exa.research.get(researchId, { stream: true, ...opts })
        for await (const event of streamResult) {
          process.stdout.write(JSON.stringify(event) + '\n')
        }
      } else {
        await executeAndPrint(async () => exa.research.get(researchId, opts))
      }
      break
    }

    case 'poll': {
      const researchId = requireArg(arg1, 'research-id')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () => exa.research.pollUntilFinished(researchId, opts))
      break
    }

    case 'run': {
      const instructions = requireArg(arg1, 'instructions')
      const opts: Record<string, unknown> = process.argv[4]
        ? (JSON.parse(process.argv[4]) as Record<string, unknown>)
        : {}
      const created = await exa.research.create({
        instructions,
        model:
          (opts.model as 'exa-research-fast' | 'exa-research' | 'exa-research-pro') ?? undefined,
        outputSchema: (opts.outputSchema as Record<string, unknown>) ?? undefined,
      })
      const createdTyped = created as { researchId: string }
      console.error(`Research task created: ${createdTyped.researchId} — polling...`)
      await executeAndPrint(async () =>
        exa.research.pollUntilFinished(createdTyped.researchId, {
          pollInterval: (opts.pollInterval as number) || 2000,
          timeoutMs: (opts.timeoutMs as number) || 600000,
          events: opts.events as boolean | undefined,
        }),
      )
      break
    }

    case 'list': {
      const opts: Record<string, unknown> = arg1
        ? (JSON.parse(arg1) as Record<string, unknown>)
        : {}
      await executeAndPrint(async () => exa.research.list(opts))
      break
    }

    default:
      console.error(`Error: Unknown subcommand "${subcommand}".`)
      console.error('Valid subcommands: create, get, poll, list, run')
      process.exit(1)
  }
} catch (err) {
  handleError(err)
}

import { readFileSync } from 'node:fs'
import { Exa } from 'exa-js'

/** Create an Exa client instance. Requires EXA_API_KEY env var. */
export function createClient(): Exa {
  return new Exa()
}

/** Require a CLI argument, exit with error if missing. */
export function requireArg(value: string | undefined, name: string): string {
  if (!value) {
    console.error(`Error: ${name} is required`)
    process.exit(1)
  }
  return value
}

/** Execute an async API call, print JSON result, exit on error. */
export async function executeAndPrint<T>(apiCall: () => Promise<T>): Promise<void> {
  try {
    const result = await apiCall()
    console.log(JSON.stringify(result, null, 2))
  } catch (err) {
    handleError(err)
  }
}

/**
 * Show help text extracted from the JSDoc comment at the top of a script file.
 * Reads lines starting with " * " until " * /" is found.
 */
export function showHelp(scriptUrl: string): void {
  const lines: string[] = []
  const src = readFileSync(new URL(scriptUrl), 'utf8')
  for (const line of src.split('\n')) {
    if (line.startsWith(' * ') || line.startsWith(' */')) {
      if (line.startsWith(' */')) break
      lines.push(line.slice(3))
    }
  }
  console.log(lines.join('\n'))
  process.exit(0)
}

/**
 * Ensure EXA_API_KEY is set. Exits with an error message if not.
 */
export function requireApiKey(): void {
  if (!process.env.EXA_API_KEY) {
    console.error('Error: EXA_API_KEY environment variable is required.')
    console.error('Get one at: https://dashboard.exa.ai/api-keys')
    process.exit(1)
  }
}

/**
 * Parse CLI args: show help if --help or no args, return query and options.
 */
export function parseArgs(scriptUrl: string): { query: string; opts: Record<string, unknown> } {
  const args = process.argv.slice(2)

  if (args.includes('--help') || args.length === 0) {
    showHelp(scriptUrl)
  }

  const query = requireArg(args[0], 'query')
  const opts: Record<string, unknown> = args[1]
    ? (JSON.parse(args[1]) as Record<string, unknown>)
    : {}

  return { query, opts }
}

/**
 * Standardized error handler for all exa scripts.
 */
export function handleError(err: unknown): never {
  console.error(`Error: ${(err as Error).message}`)
  process.exit(1)
}

/**
 * Pick allowed keys from an options object, skipping undefined values.
 */
export function filterOptions(
  opts: Record<string, unknown>,
  keys: readonly string[],
): Record<string, unknown> {
  const filtered: Record<string, unknown> = {}
  for (const key of keys) {
    if (opts[key] !== undefined) filtered[key] = opts[key]
  }
  return filtered
}

/**
 * Build contents options from text/highlights/summary fields.
 */
export function buildContentsOptions(opts: Record<string, unknown>): Record<string, unknown> {
  let contentsOpts: Record<string, unknown> = {}
  if (opts.text === true) contentsOpts.text = true
  else if (typeof opts.text === 'object') contentsOpts.text = opts.text
  if (opts.highlights === true) contentsOpts.highlights = true
  else if (typeof opts.highlights === 'object') contentsOpts.highlights = opts.highlights
  if (opts.summary === true) contentsOpts.summary = true
  else if (typeof opts.summary === 'object') contentsOpts.summary = opts.summary
  if (typeof opts.contents === 'object')
    contentsOpts = { ...contentsOpts, ...(opts.contents as Record<string, unknown>) }
  return contentsOpts
}

import { PostHogError } from './posthog-client.js'
import type { PostHogConfig } from './posthog-client.js'
import * as spec from './dashboard-spec.js'

// ---------------------------------------------------------------------------
// Config types
// ---------------------------------------------------------------------------

export interface AppConfig extends PostHogConfig {
  achInsightId: string
  dashboardName: string
}

// ---------------------------------------------------------------------------
// Config resolution
// ---------------------------------------------------------------------------

export function resolveConfig(): AppConfig {
  return {
    host: process.env['POSTHOG_HOST'] ?? 'https://us.posthog.com',
    projectId: process.env['POSTHOG_PROJECT_ID'] ?? '39507',
    token: process.env['POSTHOG_PERSONAL_API_KEY'] ?? '',
    achInsightId: process.env['POSTHOG_ACH_INSIGHT_ID'] ?? 'drOq2lO5',
    dashboardName: process.env['POSTHOG_DASHBOARD_NAME'] ?? spec.name,
  }
}

export function requireToken(config: AppConfig): void {
  if (!config.token) {
    process.stderr.write(
      'Error: POSTHOG_PERSONAL_API_KEY is required for this command.\n' +
        'Set it in your environment: export POSTHOG_PERSONAL_API_KEY=phx_...\n',
    )
    process.exit(1)
  }
}

// ---------------------------------------------------------------------------
// Output helpers
// ---------------------------------------------------------------------------

export function out(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n')
}

export function info(msg: string): void {
  process.stderr.write(msg + '\n')
}

export function handleApiError(err: unknown, context?: string): never {
  if (err instanceof PostHogError) {
    if (err.status === 401) {
      process.stderr.write(
        `Error: PostHog returned 401 (Unauthorized) on ${err.endpoint}\n` +
          'Verify that POSTHOG_PERSONAL_API_KEY is valid and has not expired.\n',
      )
    } else if (err.status === 403) {
      process.stderr.write(
        `Error: PostHog returned 403 (Forbidden) on ${err.endpoint}\n` +
          'Check that your API key has these scopes: dashboard:read, dashboard:write, insight:read, insight:write, query:read\n',
      )
    } else if (err.status === 429) {
      process.stderr.write(
        `Error: PostHog rate limit exceeded on ${err.endpoint} — tried 3 times.\n`,
      )
    } else {
      process.stderr.write(`Error: ${context ?? 'PostHog request failed'}: ${err.message}\n`)
    }
  } else {
    const message = err instanceof Error ? err.message : String(err)
    process.stderr.write(`Error: Connection to PostHog failed: ${message}\n`)
  }
  process.exit(1)
}

